# Read and process Excel files from the uv-vis
def read_excel(file):
    excel_data = pd.ExcelFile(file)
    sheets = excel_data.sheet_names
    data = {}
    for sheet in sheets:
        try:
            df = excel_data.parse(sheet)
            if len(df.columns) >= 2:
                data[f"{file.name} - {sheet}"] = df
        except Exception as e:
            st.warning(f"Couldn't read sheet '{sheet}': {e}")
            continue
    return data

# Baseline correction at 600 nm
def baseline_correct(df):
    x_values = df.iloc[:, 0].to_numpy()
    y_values = df.iloc[:, 1].to_numpy()
    baseline = np.interp(600, x_values, y_values) if 600 not in x_values else y_values[np.where(x_values == 600)][0]
    return x_values, y_values - baseline

# ZOOOOOOOOOM
def set_axis_limits(ax,x_min,x_max,x,y_all):
    y_visible_values = []

    for y in y_all:
        mask = (x >= x_min) & (x <= x_max)
        y_visible = y[mask]
        if len(y_visible) > 0:
            y_visible_values.append(y_visible)

    # Compute y-limits from all visible y-values
    if y_visible_values:
        y_combined = np.concatenate(y_visible_values)
    else:
        st.warning("No data in selected x-range.")
    ax.set_xlim(x_min, x_max)
    ax.set_ylim(y_combined.min(), y_combined.max())
    return ax

# Plot selected graphs
def plot_data(data, selected_sheets, x_range=(250, 400), y_range=(0, 2)):
    fig, ax = plt.subplots(figsize=(10, 6))
    y_all = []
    for sheet in selected_sheets:
        if sheet == "Standard Dis":
            x_std, y_stddis, y_worstdis = get_standard_curve("Dis")
            y_all.append(y_stddis)
            y_all.append(y_worstdis)
            ax.plot(x_std, y_stddis, label="Best Jan Dis curve T:41.9 W:100 P:0.05 F:5 BH:70", linestyle="--", color="red")
            ax.plot(x_std, y_worstdis, label="Worst Jan Dis Curve T:41.2 W:100 P:0.05 F:5 BH:50", linestyle=":", color="blue")
        elif sheet == "Standard Deg":
            x_std, y_stddeg, y_worstdeg = get_standard_curve("Deg")
            y_all.append(y_stddeg)
            y_all.append(y_worstdeg)
            ax.plot(x_std, y_stddeg, label="Best Jan Deg curve", linestyle="--", color="red")
            ax.plot(x_std, y_worstdeg, label="Worst Jan Deg Curve", linestyle=":", color="blue")
        elif sheet == "Standard Feed":            
            x_std, y_stdfeed, y_worstfeed = get_standard_curve("Feed")
            y_all.append(y_stdfeed)
            y_all.append(y_worstfeed)
            ax.plot(x_std, y_stdfeed, label="Best Jan Feed curve", linestyle="--", color="red")
            ax.plot(x_std, y_worstfeed, label="Worst Jan Feed Curve", linestyle=":", color="blue")
        else:
            df = data[sheet]
            df_params = pd.read_excel(excel_filename_all)
            x, y = baseline_correct(df)
            y_all.append(y)
            try:
                row = df_params[df_params["Sample ID"] == sheet.split(" - ")[1]]
                if not row.empty:
                    params = row.iloc[0].to_dict()  # Get first match, can use collum names since now dictionary
                    #print(params["Pressure (Torr)"])
                    if not params["Pressure (Torr)"]=="N/A":
                        #print(params["DDA Temperature (C)"])
                        legend_label = sheet.split(" - ")[1]+" P:"+str(params["Pressure (Torr)"])+" T:"+str(params["DDA Temperature (C)"])+" F:"+str(params["Feed Rate (kg/hr)"])+" W:"+str(params["Wiper Speed (RPM)"])+" BH: "+str(params["Band Heater Temperature (C)"])
                    else:
                        print("value error")
                        legend_label = sheet.split(" - ")[1]
                else:
                    legend_label = sheet.split(" - ")[1]
            except ValueError:
                print("value error")
                legend_label = sheet.split(" - ")[1]
            except UnboundLocalError:
                legend_label = sheet.split(" - ")[1]
                print("local error")
            except KeyError:
                legend_label = sheet.split(" - ")[1]
                print("key error")
            
            ax.plot(x, y, label=legend_label)
    ax.set_xlim(x_range)
    ax.set_ylim(y_range)
    if st.checkbox("Zoom x axis"):
        x_min = st.number_input("X-axis minimum", value=340., min_value=float(x.min()), max_value=float(x.max()))
        x_max = st.number_input("X-axis maximum", value=360., min_value=float(x.min()), max_value=float(x.max()))
        if x_min >= x_max:
            st.error("x_min must be less than x_max.")
        ax = set_axis_limits(ax,x_min,x_max,x,y_all)
    
    ax.set_xlabel("Wavelength (nm)", fontsize=16, fontweight="bold")
    ax.set_ylabel("Absorption (AU)", fontsize=16, fontweight="bold")
    ax.tick_params(axis="both", labelsize=14)
    ax.legend(fontsize=14)   
    ax.legend(loc='upper center', bbox_to_anchor=(0.5, -0.15), ncol=2)
    return fig



# Save graph and input data

def save_information():
    # Ensure folder exists
    if not os.path.exists(formatted_date):
        os.makedirs(formatted_date)

    # Save input data
    data = {
        "Date Analysed": QA_date, "Sample Time": sample_time, "Sample ID": sample_id,
        "DDA Temperature (C)": temperature, "Band Heater Temperature (C)": BH, "Pressure (Torr)": pressure, "Wiper Speed (RPM)": wiper_speed,
        "Feed Rate (kg/hr)": feed_rate, "Sample Port": sample_port, "Sampler Name": sampler_name,
        "Turbidity (NTU)": turbidity, "Density (g/ml)": density, "Comments": comments
    }
    df = pd.DataFrame([data])

    if os.path.exists(excel_filename):
        # Load existing data and append new row
        with pd.ExcelWriter(excel_filename, mode="a", engine="openpyxl", if_sheet_exists="overlay") as writer:
            df.to_excel(writer, index=False, header=False, startrow=writer.sheets["Sheet1"].max_row)
    else:
        # Create new Excel file with headers
        df.to_excel(excel_filename, index=False, engine="openpyxl")

    st.success(f"Data saved to: {excel_filename}")

    if os.path.exists(excel_filename_all):
        # Load existing data and append new row
        with pd.ExcelWriter(excel_filename_all, mode="a", engine="openpyxl", if_sheet_exists="overlay") as writer:
            df.to_excel(writer, index=False, header=False, startrow=writer.sheets["Sheet1"].max_row)
    else:
        # Could not find QA record
        st.error("Could not find QA record - record not appended")

    st.success(f"Data saved to: {excel_filename_all}")



def save_graph(fig, graph_title):

    # Ensure folder exists
    if not os.path.exists(formatted_date):
        os.makedirs(formatted_date)

    #find graph number
    max_num = 0  # Start from 0
    for file_name in os.listdir(formatted_date):
        print("Checking file:", file_name)
        match = re.match(r"^Fig(\d{2})", file_name)
        print("Match result:", match.group(1) if match else "No match")
        if match:
            num = int(match.group(1))
            if num > max_num:
                max_num = num
    max_num+=1
    # Save graph
    graph_path = os.path.join(formatted_date, f"Fig{max_num:02}_{graph_title}.png")
    fig.savefig(graph_path, format="png", bbox_inches="tight")

    st.success(f"Graph saved to: {graph_path}")


# Generate PowerPoint 
def generate_shift_report():
    prs = Presentation()
    
    # Slide 1: Date, Shift, Sampler Name
    slide_1 = prs.slides.add_slide(prs.slide_layouts[5])
    slide_1.shapes.title.text = f"Date: {formatted_date}\nShift: {shift_code}\nSampler: {sampler_name}"

    # Slide 2: Create a Table for Today's Data
    print(excel_filename)
    if os.path.exists(excel_filename):
        names=[]
        wipers=[]
        temps=[]
        BHs=[]
        pressures=[]
        feeds=[]
        df = pd.read_excel(excel_filename, engine="openpyxl")  
    headers = ["Sample ID", "Band Heater Temperature (C)", "DDA Temperature (C)", "Pressure (Torr)",
           "Wiper Speed (RPM)", "Feed Rate (kg/hr)", "Turbidity (NTU)"]
    for slide_start in range(0, len(df), fmax_rows_in_slide):
        chunk = df.iloc[slide_start:slide_start + fmax_rows_in_slide]
        slide = prs.slides.add_slide(prs.slide_layouts[6])  # blank layout

        table_shape = slide.shapes.add_table(len(chunk)*2 + 1, len(headers), Inches(0.5), Inches(1.0), Inches(9), Inches(5))
        table = table_shape.table
        tbl =  table_shape._element.graphic.graphicData.tbl
        style_id = '{FABFCF23-3B69-468F-B69F-88F6DE6A72F2}'
        tbl[0][-1].text = style_id

        # Header
        for i, h in enumerate(headers):
            table.cell(0, i).text = h

        # Rows
        for j, row in chunk.iterrows():
            idx = j - slide_start  # local row index
            table.cell(2*idx + 1, 0).merge(table.cell(2*idx + 2, 0))
            table.cell(2*idx + 1, 1).merge(table.cell(2*idx + 1, len(headers)-1))

            for i, h in enumerate(headers):
                table.cell(2*idx + 2, i).text = str(row[h])
                table.cell(2*idx + 1, i).text = str(row["Sample ID"])

            # Customize row info if needed
            port, run = "", ""
            if row["Sample ID"][6] == "D":
                port = "distillate port (06)"
            elif row["Sample ID"][6] == "R":
                port = "residual port (04)"
            elif row["Sample ID"][6] == "F":
                port = "feed port (01)"

            sid = row["Sample ID"]
            if sid[7:10] == "Deg":
                run = "degassing"
            elif sid[7:10] == "Dis":
                run = "distillation run 2" if sid[11] == "i" else "distillation run 1"

            table.cell(2*idx + 1, 1).text = f"Sampled {row['Date Analysed']} {row['Sample Time']}, from {port} during {run}"
    

    # Slide 3+: Add all PNGs from today's folder
    #print(formatted_date)
    if os.path.exists(formatted_date):
        images = sorted(f for f in os.listdir(formatted_date) if f.endswith(".png"))

        for image in images:
            slide = prs.slides.add_slide(prs.slide_layouts[5])
            slide.shapes.title.text = image.removesuffix(".png")

            # Get image size in pixels
            img_path = os.path.join(formatted_date, image)
            with Image.open(img_path) as im:
                px_width, px_height = im.size

            # Define desired width (in inches) and compute height preserving aspect ratio
            max_width_in = 8  # adjust as needed
            aspect_ratio = px_height / px_width
            width = Inches(max_width_in)
            height = Inches(max_width_in * aspect_ratio)

            # Optionally adjust top and left to center
            left = Inches((10 - max_width_in) / 2)
            top = Inches(1.3)

            slide.shapes.add_picture(img_path, left, top, width=width, height=height)
   # Save PowerPoint
    ppt_path = f"DDA_QA_{formatted_date}_{shift_code}_Report.pptx"
    prs.save(ppt_path)
    st.success(f"Shift Report saved as {ppt_path}")

